/*
  # componentes_habilidades: adiciona tipo_prova e rede + recarga a partir da planilha

  Contexto:
    A tabela `componentes_habilidades` passa a ser a REFERENCIA CANONICA de descritores das
    3 avaliacoes (prova-parana, mais, parceiro). Antes ela tinha ~160 linhas que, na pratica,
    eram apenas os descritores do 'parceiro' (incompletos).

  Mudancas:
    1. Adiciona colunas `tipo_prova` (prova-parana|mais|parceiro) e `rede`.
    2. Recarrega a tabela com 484 descritores distintos extraidos da planilha
       "Descritores Provas SAEP" / aba "Copia de Descritores".
       - Deduplicacao por (tipo_prova, ano_escolar, componente, posicao) -> descricao estavel.
       - As 3 edicoes "PARANA RECOMPOSICAO" colapsam em tipo_prova='prova-parana';
         a habilidade/habilidade_posicao guardada e a da edicao mais recente (2026).
       - Mapeamentos: ENSINO MEDIO 1a/2a/3a SERIE -> 1o/2o/3o ano; FUNDAMENTAL 6o..9o -> 6o..9o ano.
    3. Chave natural UNIQUE (tipo_prova, ano_escolar, componente, posicao) + indice de lookup.

  IMPORTANTE: rode ANTES da migration de FK (20260712120100), pois a recarga gera novos id.
*/

ALTER TABLE componentes_habilidades
  ADD COLUMN IF NOT EXISTS tipo_prova text,
  ADD COLUMN IF NOT EXISTS rede text;

-- Recarga completa a partir da planilha (484 descritores distintos)
DELETE FROM componentes_habilidades;


-- tipo_prova obrigatorio e restrito aos 3 sistemas
ALTER TABLE componentes_habilidades
  ALTER COLUMN tipo_prova SET NOT NULL;

ALTER TABLE componentes_habilidades
  DROP CONSTRAINT IF EXISTS componentes_habilidades_tipo_prova_check;
ALTER TABLE componentes_habilidades
  ADD CONSTRAINT componentes_habilidades_tipo_prova_check
  CHECK (tipo_prova IN ('prova-parana','mais','parceiro'));

-- Chave natural: um descritor por (tipo_prova, ano_escolar, componente, posicao)
ALTER TABLE componentes_habilidades
  DROP CONSTRAINT IF EXISTS componentes_habilidades_natural_key;
ALTER TABLE componentes_habilidades
  ADD CONSTRAINT componentes_habilidades_natural_key
  UNIQUE (tipo_prova, ano_escolar, componente, posicao);

CREATE INDEX IF NOT EXISTS idx_componentes_habilidades_lookup
  ON componentes_habilidades (tipo_prova, ano_escolar, componente, posicao);
